"#!/usr/bin/env python3
import os
from pathlib import Path

def search_dir(dir_path, query):
    print(f"Searching in: {dir_path} for '{query}'...")
    found = False
    for root, dirs, files in os.walk(dir_path):
        # Skip node_modules, .next, .git
        if any(x in root for x in ["node_modules", ".next", ".git"]):
            continue

        for file in files:
            # Skip binary files
            if file.endswith((".png", ".jpg", ".webp", ".pdf", ".pickle", ".exe", ".ico", ".svg")):
                continue

            fp = Path(root) / file
            try:
                content = fp.read_text(encoding="utf-8", errors="ignore")
                if query.lower() in content.lower():
                    print(f"FOUND in: {fp}")
                    # Print matching lines
                    for i, line in enumerate(content.splitlines(), 1):
                        if query.lower() in line.lower():
                            print(f"  Line {i}: {line.strip()}")
                    found = True
            except Exception as e:
                pass
    if not found:
        print("  No matches found.")

def main():
    query = "thomas.reynolds.aia@gmail.com"
    # Search local repo
    search_dir(r"c:\Users\thoma\Dropbox\My Documents\Websites\tiktokarchitect", query)
    # Search Y: drive
    search_dir(r"y:\tiktokarchitect", query)

    # Try searching for a subset "thomas" as well just in case
    print("\n--- Searching for 'thomas' subset ---")
    search_dir(r"c:\Users\thoma\Dropbox\My Documents\Websites\tiktokarchitect", "thomas.reynolds")

if __name__ == "__main__":
    main()
"

