"#!/usr/bin/env python3
"""
Sync Logs — copies local agent conversation transcripts and artifacts from
the App Data directory (.gemini folder) into the repository's docs/system_generated_logs/ directory.
Converts raw JSONL transcripts into readable Markdown format.
"""

import json
import os
import re
import sys
import shutil
from datetime import datetime
from pathlib import Path

# Force standard streams to use UTF-8 on Windows
if sys.platform.startswith("win"):
    try:
        sys.stdout.reconfigure(encoding='utf-8')
        sys.stderr.reconfigure(encoding='utf-8')
    except AttributeError:
        pass

def format_timestamp(ts_str):
    """Parse and format ISO timestamp to readable local-like format."""
    if not ts_str:
        return ""
    try:
        dt = datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
        return dt.strftime("%Y-%m-%d %H:%M:%S UTC")
    except Exception:
        return ts_str

def parse_transcript_to_markdown(jsonl_path, conv_id):
    """Parse raw jsonl transcript and return a readable markdown string."""
    md_lines = []
    md_lines.append(f"# Conversation Log ({conv_id})")
    md_lines.append(f"Generated on: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
    md_lines.append("--- \n")

    if not jsonl_path.exists():
        md_lines.append("*No transcript file found.*")
        return "\n".join(md_lines)

    try:
        with open(jsonl_path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    data = json.loads(line)
                except json.JSONDecodeError:
                    continue

                source = data.get("source", "UNKNOWN")
                step_type = data.get("type", "")
                created_at = format_timestamp(data.get("created_at", ""))
                content = data.
